  import React from 'react'
  import { MDXTag } from '@mdx-js/tag'
  import useStateReducer from "./useStateReducer"

const layoutProps = {

};
export default class MDXContent extends React.Component {
  constructor(props) {
    super(props)
    this.layout = null
  }
  render() {
    const { components, ...props } = this.props

    return <MDXTag
             name="wrapper"

             components={components}><MDXTag name="h1" components={components} props={{"id":"usestatereducer"}}>{`useStateReducer`}</MDXTag>
<MDXTag name="p" components={components}><MDXTag name="em" components={components} parentName="p">{`A setState-like reducer state manager`}</MDXTag></MDXTag>
<MDXTag name="h2" components={components} props={{"id":"usage"}}>{`Usage`}</MDXTag>

<MDXTag name="pre" components={components}><MDXTag name="code" components={components} parentName="pre" props={{"className":"language-js"}}>{`const [state, dispatch] = useStateReducer(
  { count: 0, anotherThing: 'something' },
  {
    increment: state => ({ count: state.count + 1 }),
    decrement: state => ({ count: state.count - 1 })
  }
);

// state.count -> 0
// dispatch('increment') -> 1
// dispatch('decrement') -> 0
// state -> {count: 0, anotherThing: 'something'}
`}</MDXTag></MDXTag>
           </MDXTag>
  }
}
MDXContent.isMDXComponent = true
